#include <stdio.h>
#include <string.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        char s[20]; scanf("%s",s);
        int even=0,odd=0;
        for(int i=0;s[i];++i){
            int d=s[i]-'0';
            if(d%2) odd++; else even++;
        }
        if(even>=2||odd>=2) printf("YES\n");
        else printf("NO\n");
    }
    return 0;
}

