import sys

def solve():
    data=sys.stdin.read().strip().split()
    if not data: return
    t=int(data[0])
    out=[]
    idx=1
    for _ in range(t):
        s=data[idx]; idx+=1
        even=odd=0
        for ch in s:
            if (ord(ch)-48)%2:
                odd+=1
            else:
                even+=1
        out.append('YES' if even>=2 or odd>=2 else 'NO')
    sys.stdout.write('\n'.join(out))

if __name__=='__main__':
    solve()

